function validate(args, output) {
    const aliceSizes = args[0], bobSizes = args[1];
    if (!Array.isArray(output) || output.length !== 2) return false;
    const a = output[0], b = output[1];
    if (!aliceSizes.includes(a) || !bobSizes.includes(b)) return false;
    const sumA = aliceSizes.reduce((s, x) => s + x, 0);
    const sumB = bobSizes.reduce((s, x) => s + x, 0);
    return sumA - a + b === sumB - b + a;
}

