class Solution:
    def fairCandySwap(self, aliceSizes, bobSizes):
        # Brute force: try every pair
        sumA = sum(aliceSizes)
        sumB = sum(bobSizes)
        for a in aliceSizes:
            for b in bobSizes:
                if sumA - a + b == sumB - b + a:
                    return [a, b]
        return []

