class Solution:
    def fairCandySwap(self, aliceSizes, bobSizes):
        sumA = sum(aliceSizes)
        sumB = sum(bobSizes)
        diff = (sumA - sumB) // 2
        bob_set = set(bobSizes)
        for a in aliceSizes:
            b = a - diff
            if b in bob_set:
                return [a, b]
        return []

